10	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
11	
12	export function quote(input: { yearsWithMHPCO: number; items: Item[] }): number {
13	  const itemsBaseTotal = input.items.reduce(
14	    (sum, item) => sum + BASE_PREMIUM_BY_ITEM_TYPE[item.type],
15	    0
16	  );
17	  return itemsBaseTotal + PROCESSING_FEE;
18	}
